12	import kotlinx.coroutines.flow.asStateFlow
13	import kotlinx.coroutines.launch
14	import javax.inject.Inject
15	
16	data class AuditLogUiState(
17	    val events: List<AuditEvent> = emptyList(),
18	    val isLoading: Boolean = true,
19	    val errorMessage: String? = null,
20	    val currentPage: Int = 0,
21	    val hasMore: Boolean = true
22	)
23	
24	@HiltViewModel
25	class AuditLogViewModel @Inject constructor(
26	    private val viewAuditLogUseCase: ViewAuditLogUseCase
27	) : ViewModel() {
28	
29	    companion object {
30	        private const val PAGE_SIZE = 50
31	    }
32	
33	    private val _uiState = MutableStateFlow(AuditLogUiState())
34	    val uiState: StateFlow<AuditLogUiState> = _uiState.asStateFlow()
35	
36	    init {
37	        loadPage(0)
38	    }
39	
40	    fun loadPage(page: Int) {
41	        viewModelScope.launch(Dispatchers.IO) {
42	            _uiState.value = _uiState.value.copy(isLoading = true)
43	            when (val result = viewAuditLogUseCase.getEventsPaged(PAGE_SIZE, page * PAGE_SIZE)) {
44	                is AppResult.Success -> {
45	                    val newEvents = if (page == 0) {
46	                        result.data
47	                    } else {
48	                        _uiState.value.events + result.data
49	                    }
50	                    _uiState.value = _uiState.value.copy(
51	                        events = newEvents,
52	                        isLoading = false,
53	                        currentPage = page,
54	                        hasMore = result.data.size == PAGE_SIZE
55	                    )
56	                }
57	                is AppResult.PermissionError -> {
58	                    _uiState.value = _uiState.value.copy(
59	                        isLoading = false,
60	                        errorMessage = "Permission denied: requires audit.view"
61	                    )
62	                }
63	                else -> {
64	                    _uiState.value = _uiState.value.copy(
65	                        isLoading = false,
66	                        errorMessage = "Failed to load audit events"
67	                    )
68	                }
69	            }
70	        }
71	    }
72	
73	    fun loadNextPage() {
74	        if (!_uiState.value.isLoading && _uiState.value.hasMore) {
75	            loadPage(_uiState.value.currentPage + 1)
76	        }
77	    }
78	
79	    fun refresh() {
80	        loadPage(0)
81	    }
82	}
