import com.learnmart.app.domain.model.*
import com.learnmart.app.domain.repository.AuditRepository
import com.learnmart.app.domain.repository.AssessmentRepository
import com.learnmart.app.domain.usecase.auth.CheckPermissionUseCase
import com.learnmart.app.security.SessionManager
import com.learnmart.app.util.AppResult
import com.google.common.truth.Truth.assertThat
import io.mockk.*
import kotlinx.coroutines.test.runTest
import org.junit.Before
import org.junit.Test
import java.time.Instant

class AssessmentFinalizationTest {
    private lateinit var assessmentRepository: AssessmentRepository
    private lateinit var auditRepository: AuditRepository
    private lateinit var checkPermission: CheckPermissionUseCase
    private lateinit var sessionManager: SessionManager
    private lateinit var useCase: ManageAssessmentUseCase

    private val now = Instant.now()

    @Before
    fun setUp() {
        assessmentRepository = mockk(relaxed = true)
        auditRepository = mockk(relaxed = true)
        checkPermission = mockk()
        sessionManager = mockk()
        every { sessionManager.getCurrentUserId() } returns "instructor-1"
        every { sessionManager.getCurrentSessionId() } returns "session-1"
        coEvery { checkPermission.hasPermission(Permission.ASSESSMENT_GRADE) } returns true
        useCase = ManageAssessmentUseCase(assessmentRepository, auditRepository, checkPermission, sessionManager)
    }

    private fun makeSubmission(status: SubmissionStatus) = Submission(
        id = "sub-1", assessmentId = "assess-1", learnerId = "learner-1",
        status = status, startedAt = now, submittedAt = now,
        totalScore = null, maxScore = 100, gradePercentage = null,
        gradedBy = null, gradedAt = null, finalizedAt = null,
        versionNumber = 1, createdAt = now, updatedAt = now, version = 1
    )

    private fun makeQueueItem(id: String, status: GradeQueueStatus) = SubjectiveGradeQueueItem(
        id = id, submissionId = "sub-1", submissionAnswerId = "ans-$id",
        questionId = "q-$id", assessmentId = "assess-1", classOfferingId = "class-1",
        assignedGraderId = null, assignedRoleType = RoleType.INSTRUCTOR,
        status = status, createdAt = now, updatedAt = now
    )

    @Test
    fun `incomplete grading does not finalize submission`() = runTest {
        val queueItem = makeQueueItem("qi-1", GradeQueueStatus.PENDING)
        coEvery { assessmentRepository.getGradeQueueItemById("qi-1") } returns queueItem
        coEvery { assessmentRepository.getQuestionById("q-qi-1") } returns Question(
            id = "q-qi-1", questionBankId = "bank-1", questionType = QuestionType.SUBJECTIVE,
            difficulty = DifficultyLevel.MEDIUM, questionText = "Explain X",
            explanation = null, points = 50, tagIds = emptyList(),
            createdBy = "inst-1", createdAt = now, updatedAt = now, version = 1
        )

        // After grading qi-1, there's still a pending item qi-2
        coEvery { assessmentRepository.getQueueItemsForSubmission("sub-1") } returns listOf(
            makeQueueItem("qi-1", GradeQueueStatus.GRADED),
            makeQueueItem("qi-2", GradeQueueStatus.PENDING)
        )

        val result = useCase.gradeSubjectiveAnswer("qi-1", 40, "Good work")
        assertThat(result).isInstanceOf(AppResult.Success::class.java)

        // Should NOT update submission to FINALIZED since qi-2 is still pending
        coVerify(exactly = 0) {
            assessmentRepository.updateSubmission(match { it.status == SubmissionStatus.FINALIZED })
        }
    }

    @Test
    fun `complete grading finalizes submission`() = runTest {
        val queueItem = makeQueueItem("qi-1", GradeQueueStatus.PENDING)
        val submission = makeSubmission(SubmissionStatus.QUEUED_FOR_MANUAL_REVIEW)

        coEvery { assessmentRepository.getGradeQueueItemById("qi-1") } returns queueItem
        coEvery { assessmentRepository.getQuestionById("q-qi-1") } returns Question(
            id = "q-qi-1", questionBankId = "bank-1", questionType = QuestionType.SUBJECTIVE,
            difficulty = DifficultyLevel.MEDIUM, questionText = "Explain X",
            explanation = null, points = 50, tagIds = emptyList(),
            createdBy = "inst-1", createdAt = now, updatedAt = now, version = 1
        )

        // All items graded after this grading action
        coEvery { assessmentRepository.getQueueItemsForSubmission("sub-1") } returns listOf(
            makeQueueItem("qi-1", GradeQueueStatus.GRADED)
        )
        coEvery { assessmentRepository.getSubmissionById("sub-1") } returns submission
        coEvery { assessmentRepository.getAnswersForSubmission("sub-1") } returns listOf(
            SubmissionAnswer(
                id = "ans-qi-1", submissionId = "sub-1", questionId = "q-qi-1",
                answerText = "My answer", selectedChoiceIds = emptyList(),
                score = null, maxScore = 50, isAutoGraded = false,
                feedback = null, submittedAt = now
            )
        )
        coEvery { assessmentRepository.getObjectiveGradeResult("ans-qi-1") } returns null
        coEvery { assessmentRepository.getGradeDecision("ans-qi-1") } returns GradeDecision(
            id = "gd-1", submissionAnswerId = "ans-qi-1", gradedBy = "instructor-1",
            score = 40, maxScore = 50, feedback = "Good", gradedAt = now
        )

        val result = useCase.gradeSubjectiveAnswer("qi-1", 40, "Good work")
        assertThat(result).isInstanceOf(AppResult.Success::class.java)

        // Should update submission to FINALIZED
        coVerify {
            assessmentRepository.updateSubmission(match { it.status == SubmissionStatus.FINALIZED })
        }
    }

    @Test
    fun `grading uses submission-scoped queue not empty class filter`() = runTest {
        val queueItem = makeQueueItem("qi-1", GradeQueueStatus.PENDING)
        coEvery { assessmentRepository.getGradeQueueItemById("qi-1") } returns queueItem
        coEvery { assessmentRepository.getQuestionById("q-qi-1") } returns Question(
            id = "q-qi-1", questionBankId = "bank-1", questionType = QuestionType.SUBJECTIVE,
            difficulty = DifficultyLevel.MEDIUM, questionText = "Explain X",
            explanation = null, points = 50, tagIds = emptyList(),
            createdBy = "inst-1", createdAt = now, updatedAt = now, version = 1
        )
        coEvery { assessmentRepository.getQueueItemsForSubmission("sub-1") } returns listOf(
            makeQueueItem("qi-1", GradeQueueStatus.GRADED)
        )
        coEvery { assessmentRepository.getSubmissionById("sub-1") } returns
            makeSubmission(SubmissionStatus.QUEUED_FOR_MANUAL_REVIEW)
        coEvery { assessmentRepository.getAnswersForSubmission("sub-1") } returns emptyList()

        useCase.gradeSubjectiveAnswer("qi-1", 40, "Good")

        // Verify it calls getQueueItemsForSubmission, NOT getPendingQueueByClassOffering("")
        coVerify { assessmentRepository.getQueueItemsForSubmission("sub-1") }
        coVerify(exactly = 0) { assessmentRepository.getPendingQueueByClassOffering("") }
    }
}
"}

