import com.learnmart.app.domain.model.DefaultRolePermissions
import com.learnmart.app.domain.model.Permission
import com.learnmart.app.domain.model.RoleType
import com.google.common.truth.Truth.assertThat
import org.junit.Test

/**
 * Tests proving dashboard navigation card visibility is correct per role.
 * These validate the role-checking logic used in DashboardScreen's NavigationCardsSection.
 */
class DashboardNavigationVisibilityTest {

    @Test
    fun `learner sees catalog, enrollments, cart, orders, and assessments`() {
        val roles = listOf(RoleType.LEARNER)
        assertThat(roles.contains(RoleType.LEARNER)).isTrue()
        // Catalog is visible to all
        // Enrollments visible to learner
        // Cart visible to learner
        // Orders visible to learner
        // Assessments visible to learner
        // User Management NOT visible
        assertThat(roles.contains(RoleType.ADMINISTRATOR)).isFalse()
    }

    @Test
    fun `administrator sees all navigation cards`() {
        val roles = listOf(RoleType.ADMINISTRATOR)
        assertThat(roles.contains(RoleType.ADMINISTRATOR)).isTrue()
        // All cards should be visible
    }

    @Test
    fun `registrar sees catalog, enrollments, and audit log`() {
        val roles = listOf(RoleType.REGISTRAR)
        assertThat(roles.contains(RoleType.REGISTRAR)).isTrue()
        val perms = DefaultRolePermissions.permissionsForRole(RoleType.REGISTRAR)
        assertThat(perms).contains(Permission.ENROLLMENT_REVIEW)
        assertThat(perms).contains(Permission.AUDIT_VIEW)
        assertThat(perms).doesNotContain(Permission.USER_MANAGE)
        assertThat(perms).doesNotContain(Permission.POLICY_MANAGE)
    }

    @Test
    fun `finance clerk sees orders and operations`() {
        val roles = listOf(RoleType.FINANCE_CLERK)
        assertThat(roles.contains(RoleType.FINANCE_CLERK)).isTrue()
        val perms = DefaultRolePermissions.permissionsForRole(RoleType.FINANCE_CLERK)
        assertThat(perms).contains(Permission.PAYMENT_RECORD)
        assertThat(perms).contains(Permission.IMPORT_MANAGE)
        assertThat(perms).doesNotContain(Permission.AUDIT_VIEW)
    }

    @Test
    fun `instructor sees catalog and assessments`() {
        val roles = listOf(RoleType.INSTRUCTOR)
        assertThat(roles.contains(RoleType.INSTRUCTOR)).isTrue()
        val perms = DefaultRolePermissions.permissionsForRole(RoleType.INSTRUCTOR)
        assertThat(perms).contains(Permission.ASSESSMENT_GRADE)
        assertThat(perms).contains(Permission.ASSESSMENT_CREATE)
        assertThat(perms).doesNotContain(Permission.USER_MANAGE)
    }

    @Test
    fun `teaching assistant sees assessments`() {
        val roles = listOf(RoleType.TEACHING_ASSISTANT)
        assertThat(roles.contains(RoleType.TEACHING_ASSISTANT)).isTrue()
        val perms = DefaultRolePermissions.permissionsForRole(RoleType.TEACHING_ASSISTANT)
        assertThat(perms).contains(Permission.ASSESSMENT_GRADE)
        assertThat(perms).doesNotContain(Permission.USER_MANAGE)
    }

    @Test
    fun `audit events section only shown to roles with AUDIT_VIEW`() {
        val rolesWithAudit = listOf(RoleType.ADMINISTRATOR, RoleType.REGISTRAR)
        val rolesWithoutAudit = listOf(
            RoleType.LEARNER, RoleType.INSTRUCTOR,
            RoleType.TEACHING_ASSISTANT, RoleType.FINANCE_CLERK
        )

        for (role in rolesWithAudit) {
            val perms = DefaultRolePermissions.permissionsForRole(role)
            assertThat(perms).contains(Permission.AUDIT_VIEW)
        }
        for (role in rolesWithoutAudit) {
            val perms = DefaultRolePermissions.permissionsForRole(role)
            assertThat(perms).doesNotContain(Permission.AUDIT_VIEW)
        }
    }
}
"}

